const body = $input.first().json.body || $input.first().json;

let messageType = 'unknown';
let messageContent = '';
let phoneNumber = '';
let messageId = '';
let mediaId = '';
let imageCaption = '';

try {
  const entry = body.entry[0];
  const change = entry.changes[0];
  const value = change.value;

  if (!value.messages || value.messages.length === 0) {
    return [];
  }

  const msg = value.messages[0];
  phoneNumber = msg.from;
  messageId = msg.id;
  messageType = msg.type;

  if (msg.type === 'text') {
    messageContent = msg.text.body;
  } else if (msg.type === 'audio') {
    mediaId = msg.audio.id;
    messageContent = '[AUDIO]';
  } else if (msg.type === 'image') {
    mediaId = msg.image.id;
    imageCaption = msg.image.caption || '';
    messageContent = '[IMAGEN]';
  } else {
    messageType = 'unsupported';
    messageContent = msg.type;
  }
} catch (error) {
  return [];
}

return [{
  json: {
    phoneNumber,
    messageId,
    messageType,
    messageContent,
    mediaId,
    imageCaption
  }
}];

const item = $input.first().json;
const type = item.messageType;

if (type === 'text') {
  return [{ json: { ...item, route: 'text' } }];
} else if (type === 'audio') {
  return [{ json: { ...item, route: 'audio' } }];
} else if (type === 'image') {
  return [{ json: { ...item, route: 'image' } }];
} else {
  return [{ json: { ...item, route: 'unsupported' } }];
}

